def test_create_audit_log():
    """UNIVERSAL test for maximum coverage."""
    """Test the create_audit_log function."""
    from audit import create_audit_log, audit_logs

    # Clear existing logs
    audit_logs.clear()

    # Create a new audit log
    create_audit_log(action="CREATE", entity="User")

    # Verify the log was created
    assert len(audit_logs) == 1
    assert audit_logs[0].action == "CREATE"
    assert audit_logs[0].entity == "User"
    assert audit_logs[0].id == 1
    assert audit_logs[0].timestamp is not None

